{
    "code": "ct_pds",
    "description": "Table des points de services",
    "disabled": false,
    "name": "ct_pds",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "num_contrat",
            "description": "N° Contrat",
            "fieldType": "STRING"
        },
        {
            "code": "id_pds",
            "description": "Identifiant du point de service",
            "fieldType": "STRING"
        },
        {
            "code": "num_compteur",
            "description": "Numéro du compteur",
            "fieldType": "STRING"
        },
        {
            "code": "pose_pds",
            "description": "Date de pose",
            "fieldType": "DATE"
        },
        {
            "code": "depose_pds",
            "description": "Date de dépose",
            "fieldType": "DATE"
        },
        {
            "code": "index_pose",
            "description": "Index de pose",
            "fieldType": "STRING"
        },
        {
            "code": "exploitation",
            "description": "Identifiant de l’exploitation",
            "fieldType": "STRING"
        },
        {
            "code": "branchement",
            "description": "Identifiant du branchement",
            "fieldType": "STRING"
        },
        {
            "code": "tableau",
            "description": "Identifiant du tableau",
            "fieldType": "STRING"
        },
        {
            "code": "adresse",
            "description": "Localisation du point de service",
            "fieldType": "STRING"
        },
        {
            "code": "puissance",
            "description": "Puissance",
            "fieldType": "LONG"
        },
        {
            "code": "puissance_souscrite",
            "description": "Puissance souscrite",
            "fieldType": "LONG"
        },
        {
            "code": "roues",
            "description": "Nombre de roues",
            "fieldType": "LONG"
        },
        {
            "code": "cadrans",
            "description": "Nombre de cadrans",
            "fieldType": "LONG"
        },
        {
            "code": "nb_fils",
            "description": "Nombre de fils",
            "fieldType": "LONG"
        },
        {
            "code": "coefficient_lecture",
            "description": "Coefficient de lecture",
            "fieldType": "LIST",
            "listValues": {
                "0.5": 0.5,
                "1": "1"
            }
        },
        {
            "code": "puissance_transformateur",
            "description": "Puissance du transformateur",
            "fieldType": "LONG"
        },
        {
            "code": "emplacement_tc",
            "description": "Emplacement du transformateur",
            "fieldType": "LIST",
            "listValues": {
                "AVANT": "AVANT",
                "APRES": "APRES"
            }
        },
        {
            "code": "transformateur_intensite",
            "description": "Transformateur d'intensité",
            "fieldType": "BOOLEAN"
        },
        {
            "code": "gamme",
            "description": "Gamme",
            "fieldType": "STRING"
        },
        {
            "code": "longueur_conducteur",
            "description": "Longueur du conducteur",
            "fieldType": "LONG"
        },
        {
            "code": "date_resiliation_contrat",
            "description": "Date de résiliation du dernier contrat",
            "fieldType": "DATE"
        },
        {
            "code": "type_raccordement",
            "description": "Type de raccordement",
            "fieldType": "STRING"
        },
        {
            "code": "coef_tan_phi",
            "description": "Coefficient Tan Phi",
            "fieldType": "BOOLEAN"
        },
        {
            "code": "debut_validite",
            "description": "Date de début de validité",
            "fieldType": "DATE"
        },
        {
            "code": "fin_validite",
            "description": "Date de fin de validité",
            "fieldType": "DATE"
        },
        {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING"
        },
        {
            "code": "statut_pds",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "ACTIF": "ACTIF",
                "INACTIF": "INACTIF"
            }
        }
    ],
    "action": []
}

