            "listValues": {
                "BASE": "BASE",
                "HP": "HP",
                "HC": "HC",
                "JOUR": "JOUR",
                "NUIT": "NUIT"
            }
        },
        {
            "code": "nature_mesure",
            "description": "Nature de la mesure",
            "fieldType": "LIST",
            "listValues": {
                "EA": "EA",
                "ER": "ER",
                "EAi": "EAi",
                "ERi": "ERi",
                "Imax": "Imax",
                "PA": "PA",
                "DD": "DD",
                "VOL": "VOL",
                "VOLR": "VOLR",
                "COSPHI": "COSPHI",
                "DP": "DP"
            }
        },
        {
            "code": "edr_id",
            "description": "Identifiant de l’EDR associé à la consommation",
            "fieldType": "LONG"
        },
        {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING",
            "maxValue": 200
        },
        {
            "code": "statut",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "IMPORTE": "IMPORTE",
                "VALORISE": "VALORISE",
                "CALCULE": "CALCULE",
                "INFO": "INFO",
                "ERREUR": "ERREUR"
            }
        }
    ],
    "action": []
}

